export type Item = Record<string, unknown>;
export type QuoteStep = { op: "quote"; items: Item[] };
export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<{ itemType: string; amount: number }> } };
export type Step = QuoteStep | ClaimStep;
export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const itemBasePremium = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type as string] ?? 0;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE = 60;

const isComponent = (item: Item): boolean =>
  COMPONENT_TYPES.has(item.type as string);

const componentGroupBase = (count: number, unitBase: number): number => {
  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
  return count * unitBase;
};

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    const type = item.type as string;
    counts.set(type, (counts.get(type) ?? 0) + 1);
  }
  return counts;
};

const componentsBaseSum = (components: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(components)) {
    total += componentGroupBase(count, BASE_PREMIUM_BY_TYPE[type] ?? 0);
  }
  return total;
};

const mainItemsBaseSum = (mainItems: Item[]): number =>
  mainItems.reduce((sum, item) => sum + itemBasePremium(item), 0);

const itemsBaseSum = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mainItems = items.filter((item) => !isComponent(item));
  return mainItemsBaseSum(mainItems) + componentsBaseSum(components);
};

const CURSE_SURCHARGE_RATE = 0.5;

const itemCurseSurcharge = (item: Item): number =>
  item.cursed === true ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;

const itemSpecificSurchargesSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemCurseSurcharge(item), 0);

const quotePremium = (items: Item[]): number => {
  const baseSum = itemsBaseSum(items);
  const firstInsuranceSurcharge = baseSum * FIRST_INSURANCE_SURCHARGE_RATE;
  const itemSurcharges = itemSpecificSurchargesSum(items);
  return Math.ceil(baseSum + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

