    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // ---- Components and blocks ----
  it("2 runes → 50 G base premium (no block) → total 60 G (50 base + 5 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → 60 G base premium (block applies) → total 71 G (60 + 6 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes → 100 G base premium (no block) → total 115 G (100 + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → 175 G base premium → total 198 G (175 + 17.5 + 5 = 197.5, rounded up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: Array.from({ length: 7 }, () => ({ type: "rune" })),
      }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("2 runes + 1 moonstone → 75 G base premium (no block: different types) → total 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones → 120 G base premium (two separate blocks) → total 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          ...Array.from({ length: 3 }, () => ({ type: "rune" })),
          ...Array.from({ length: 3 }, () => ({ type: "moonstone" })),
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // ---- Item-specific modifiers ----
  it("cursed amulet → 60 base + 30 curse + 6 first-insurance + 5 fee = 101 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet", cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 101 }] });
  });
  it("enchanted amulet (ench 6) → 60 + 18 high-ench + 6 first-insurance + 5 fee = 89 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet", enchantment: 6 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 89 }] });
  });
  it("sword with exactly enchantment 5 → 100 + 30 + 10 + 5 = 145 G (boundary)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 → 100 + 10 + 5 = 115 G (no high-enchantment)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("cursed sword with enchantment 5 → 100 + 50 + 30 + 10 + 5 = 195 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });

  // ---- Policy-wide modifiers ----
  it("3-year customer, single amulet → 60 - 12 loyalty + 6 first-insurance + 5 fee = 59 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 59 }] });
  });
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("first insurance carries 10% surcharge per item");
  it.todo("each contract after the first gets 15% follow-up discount");

  // ---- Modifier scope on multi-item policies ----
  it.todo("cursed sword + plain amulet → 160 base + 50 curse = 210 G before further modifiers and fee");
  it.todo("item-specific modifiers apply per item; policy-wide modifiers apply to policy base; fee added last");

  // ---- Rounding ----
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
  it.todo("intermediate amounts kept as fractions; only final premium or payout rounded");

  // ---- Integration premium examples ----
  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G (100 + 50 + 10 + 5 fee)");
  it.todo("long-standing (3 yr) second contract with cursed sword (steel, ench 7) → 160 G");
  it.todo("first insurance surcharge still applies per item even on follow-up contract");

  // ---- Claim: standard reimbursement ----
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G");

  // ---- Claim: enchantment threshold ----
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench wins, then deductible)");

  // ---- Claim: dragon material ----
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins)");

  // ---- Claim: deductible per damage event ----
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (100 deductible per item)");

  // ---- Claim: multiple items of same type ----
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two sword damages on policy with two swords → each treated as separate damage with its own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero, claim rejected");

  // ---- Claim: cap exhaustion ----
  it.todo("policy with sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value; premium modifiers don't raise cap)");
  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only");
  it.todo("sword insured, cap 2000; two claims of 1500 — first payout 1400 (cap remaining 600), second payout 600 (cap remaining 0)");

  // ---- Error / edge cases ----
  it.todo("quote includes item with unknown type (e.g. broomstick) → CLI exits non-zero, error to stderr, no results to stdout");
  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero, error to stderr");
  it.todo("claim contains a damage entry with amount: -200 → CLI exits non-zero, error to stderr");

  // ---- CLI / schema integration ----
  it.todo("schema example: amulet quote then fire claim of 200 returns premium and payout/remainingCap");
});

